import{_ as l,c as r,o as t,ag as o}from"./chunks/framework.Co20b0ok.js";const g=JSON.parse('{"title":"LLMNR协议 & MDNS协议 & NBNS协议","description":"","frontmatter":{},"headers":[],"relativePath":"intranet-security/domain-basic/LLMNR协议 & MDNS协议 & NBNS协议.md","filePath":"intranet-security/domain-basic/LLMNR协议 & MDNS协议 & NBNS协议.md"}'),i={name:"intranet-security/domain-basic/LLMNR协议 & MDNS协议 & NBNS协议.md"};function n(e,a,s,N,h,p){return t(),r("div",null,a[0]||(a[0]=[o('<h1 id="llmnr协议-mdns协议-nbns协议" tabindex="-1">LLMNR协议 &amp; MDNS协议 &amp; NBNS协议 <a class="header-anchor" href="#llmnr协议-mdns协议-nbns协议" aria-label="Permalink to &quot;LLMNR协议 &amp; MDNS协议 &amp; NBNS协议&quot;">​</a></h1><h2 id="主机名解析顺序" tabindex="-1">主机名解析顺序 <a class="header-anchor" href="#主机名解析顺序" aria-label="Permalink to &quot;主机名解析顺序&quot;">​</a></h2><ol><li><p><strong>本地 hosts 文件解析</strong>：</p><p>首先系统会检查 <code>hosts</code> 文件是否有匹配的主机名解析记录。如果有，直接返回对应的 IP 地址，无需进行网络查询。</p></li><li><p><strong>DNS 解析</strong>：</p><p>如果 <code>hosts</code> 文件中没有匹配记录，则向配置的 DNS 服务器发送查询请求。如果主 DNS 服务器无法解析，还会尝试查询备用 DNS 服务器。</p></li><li><p><strong>LLMNR 解析</strong>：</p><p>DNS 解析失败时，系统会通过 LLMNR 协议发送局域网内的多播请求来解析主机名。</p></li><li><p><strong>NBNS 解析</strong>：</p><p>若 LLMNR 解析也失败，则使用 NBNS（NetBIOS Name Service）协议，通过广播查询局域网内其他设备，尝试解析主机名。</p></li></ol><h2 id="llmnr-协议" tabindex="-1"><strong>LLMNR 协议</strong> <a class="header-anchor" href="#llmnr-协议" aria-label="Permalink to &quot;**LLMNR 协议**&quot;">​</a></h2><h3 id="定义" tabindex="-1"><strong>定义</strong> <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;**定义**&quot;">​</a></h3><p>LLMNR（Link-Local Multicast Name Resolution）是一种局域网内解析主机名的协议。主要用于没有 DNS 服务器的环境，通过组播地址实现主机名解析。LLMNR 主要为 IPv6 环境设计，但也兼容 IPv4。</p><h3 id="工作过程" tabindex="-1"><strong>工作过程</strong> <a class="header-anchor" href="#工作过程" aria-label="Permalink to &quot;**工作过程**&quot;">​</a></h3><ol><li><p><strong>缓存查询</strong>：</p><p>主机首先检查内部名称缓存，寻找匹配的主机名。</p></li><li><p><strong>DNS 查询</strong>：</p><p>若缓存中没有匹配的记录，系统向配置的 DNS 服务器发送查询请求。如果 DNS 查询失败或返回错误信息，系统转为使用 LLMNR 协议。</p></li><li><p><strong>LLMNR 请求发送</strong>：</p><p>主机通过 UDP（端口号 5355）发送组播查询请求，范围限定在本地子网。</p></li><li><p><strong>LLMNR 响应处理</strong>：</p><ul><li>若局域网内有支持 LLMNR 且被配置为响应的设备，它们会将请求的主机名与自身主机名进行比较。</li><li>如果匹配成功，该设备通过单播发送包含其 IP 地址的响应消息。</li><li>请求主机收到响应后即可解析到所需的 IP 地址。</li></ul></li></ol><h3 id="特点" tabindex="-1"><strong>特点</strong> <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;**特点**&quot;">​</a></h3><ul><li>无需配置 DNS 服务器即可完成名称解析。</li><li>使用 UDP 进行组播通信，适合局域网环境，传输轻量且高效。</li><li>主要在 Windows 系统中使用。</li></ul><hr><h2 id="mdns-协议" tabindex="-1"><strong>MDNS 协议</strong> <a class="header-anchor" href="#mdns-协议" aria-label="Permalink to &quot;**MDNS 协议**&quot;">​</a></h2><h3 id="定义-1" tabindex="-1"><strong>定义</strong> <a class="header-anchor" href="#定义-1" aria-label="Permalink to &quot;**定义**&quot;">​</a></h3><p>MDNS（Multicast DNS）是一种在局域网内实现设备和服务自动发现的协议。设备通过组播地址发送 DNS 查询与响应消息，实现无需中央服务器的主机名解析与服务发现。MDNS 常用于 IoT 设备、Apple Bonjour 服务等场景。</p><h3 id="工作过程-1" tabindex="-1"><strong>工作过程</strong> <a class="header-anchor" href="#工作过程-1" aria-label="Permalink to &quot;**工作过程**&quot;">​</a></h3><ol><li><p><strong>设备启动与宣告</strong>：</p><p>新设备连接局域网时，发送宣告（Announcement）消息，包含设备的主机名、IP 地址等信息，通知局域网内其他设备。</p></li><li><p><strong>缓存与发现</strong>：</p><p>接收宣告消息的设备将该信息存入本地缓存，以便后续直接查询。</p></li><li><p><strong>查询</strong>：</p><p>当设备需要解析主机名或查找服务时，发送 MDNS 查询消息（Query），询问局域网内是否有匹配的设备。</p></li><li><p><strong>响应</strong>：</p><p>收到查询的设备检查本地缓存，若有匹配结果则发送 MDNS 响应消息（Response），提供 IP 地址或服务信息。</p></li><li><p><strong>解析与通信</strong>：</p><p>查询设备解析响应中的数据，并将其存入本地缓存，用于与目标设备通信。</p></li></ol><h3 id="特点-1" tabindex="-1"><strong>特点</strong> <a class="header-anchor" href="#特点-1" aria-label="Permalink to &quot;**特点**&quot;">​</a></h3><ul><li>基于 UDP 协议，端口号 5353。</li><li>遵循 DNS 结构与资源记录类型，无需新的操作码。</li><li>广泛应用于物联网设备、Apple 生态等场景，实现设备的自动发现与通信。</li></ul><hr><h2 id="nbns-协议" tabindex="-1"><strong>NBNS 协议</strong> <a class="header-anchor" href="#nbns-协议" aria-label="Permalink to &quot;**NBNS 协议**&quot;">​</a></h2><h3 id="定义-2" tabindex="-1"><strong>定义</strong> <a class="header-anchor" href="#定义-2" aria-label="Permalink to &quot;**定义**&quot;">​</a></h3><p>NBNS（NetBIOS Name Service）是用于在局域网中解析计算机名与 IP 地址的网络协议。主要应用于早期的 Windows 网络环境，通过 UDP 协议（端口号 137）实现名称解析。</p><h3 id="工作过程-2" tabindex="-1"><strong>工作过程</strong> <a class="header-anchor" href="#工作过程-2" aria-label="Permalink to &quot;**工作过程**&quot;">​</a></h3><ol><li><strong>名字注册</strong>： <ul><li>计算机启动时向网络发送名字注册请求，该请求包含计算机名与 IP 地址的对应关系。</li><li>请求通过广播发送到整个局域网中。</li></ul></li><li><strong>缓存保存</strong>： <ul><li>网络中的其他计算机收到该请求后，将对应关系存储在本地缓存中。</li></ul></li><li><strong>名字查询</strong>： <ul><li>当计算机需要解析其他计算机的 IP 地址时，发送名字查询请求。</li><li>该请求以广播形式发送到局域网中。</li></ul></li><li><strong>响应</strong>： <ul><li>其他计算机收到查询请求后，检查本地缓存。</li><li>若有匹配结果，直接回复查询应答，提供对应的 IP 地址。</li></ul></li><li><strong>转发查询</strong>： <ul><li>若本地缓存无匹配结果，查询请求可能被转发给其他网络节点，直到找到结果或确定无法找到。</li></ul></li></ol><h3 id="安全风险" tabindex="-1"><strong>安全风险</strong> <a class="header-anchor" href="#安全风险" aria-label="Permalink to &quot;**安全风险**&quot;">​</a></h3><ul><li><strong>明文传输</strong>：NBNS 消息未加密，容易受到中间人攻击。</li><li><strong>欺骗攻击</strong>：攻击者可发送虚假的 NBNS 响应，诱导设备将数据发送到错误地址。</li></ul>',26)]))}const u=l(i,[["render",n]]);export{g as __pageData,u as default};
